
CREATE TABLE IF NOT EXISTS public.dtc_codes (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    code VARCHAR(10) NOT NULL UNIQUE,
    description_es TEXT NOT NULL,
    description_en TEXT NOT NULL,
    system VARCHAR(50) NOT NULL,
    severity VARCHAR(20) NOT NULL,
    possible_causes TEXT NOT NULL,
    urgency VARCHAR(20) NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- Enable RLS
ALTER TABLE public.dtc_codes ENABLE ROW LEVEL SECURITY;

-- Allow public read access
CREATE POLICY "Allow public read access to dtc_codes"
ON public.dtc_codes FOR SELECT USING (true);

-- Insert data
ON CONFLICT (code) DO UPDATE SET description_es = EXCLUDED.description_es, description_en = EXCLUDED.description_en, possible_causes = EXCLUDED.possible_causes;

ON CONFLICT (code) DO UPDATE SET description_es = EXCLUDED.description_es, description_en = EXCLUDED.description_en, possible_causes = EXCLUDED.possible_causes;

ON CONFLICT (code) DO UPDATE SET description_es = EXCLUDED.description_es, description_en = EXCLUDED.description_en, possible_causes = EXCLUDED.possible_causes;

ON CONFLICT (code) DO UPDATE SET description_es = EXCLUDED.description_es, description_en = EXCLUDED.description_en, possible_causes = EXCLUDED.possible_causes;

ON CONFLICT (code) DO UPDATE SET description_es = EXCLUDED.description_es, description_en = EXCLUDED.description_en, possible_causes = EXCLUDED.possible_causes;

