INSERT INTO public.dtc_codes (code, description_es, description_en, system, severity, possible_causes, urgency) VALUES 
('P0100', 'Circuito del Sensor MAF', 'Mal funcionamiento del circuito del sensor de flujo de masa de aire.', 'ENGINE', 'MODERATE', 'Revisar cableado del sensor MAF, limpiar o reemplazar sensor, verificar fugas de aire.', 'CAUTION'),
('P0101', 'Rango/Rendimiento del Sensor MAF', 'El sensor MAF está enviando señales fuera de rango esperado.', 'ENGINE', 'MODERATE', 'Limpiar o reemplazar sensor MAF, revisar filtro de aire y conexiones eléctricas.', 'CAUTION'),
('P0102', 'Sensor MAF - Entrada Baja', 'Señal baja del circuito del sensor de flujo de masa de aire.', 'ENGINE', 'MODERATE', 'Verificar cableado, conector y sensor MAF. Posible corto a tierra.', 'CAUTION'),
('P0103', 'Sensor MAF - Entrada Alta', 'Señal alta del circuito del sensor de flujo de masa de aire.', 'ENGINE', 'MODERATE', 'Verificar cableado y conector del sensor MAF. Posible cortocircuito.', 'CAUTION'),
('P0105', 'Circuito del Sensor MAP', 'Mal funcionamiento del circuito del sensor de presión absoluta del múltiple.', 'ENGINE', 'MODERATE', 'Revisar manguera de vacío, cableado y conector del sensor MAP.', 'CAUTION'),
('P0106', 'Rango/Rendimiento del Sensor MAP', 'El sensor MAP reporta valores fuera del rango esperado.', 'ENGINE', 'MODERATE', 'Verificar fugas de vacío, limpiar o reemplazar sensor MAP.', 'CAUTION'),
('P0110', 'Circuito del Sensor IAT', 'Mal funcionamiento del circuito del sensor de temperatura del aire de admisión.', 'ENGINE', 'LOW', 'Revisar cableado y conector del sensor IAT, reemplazar si está dañado.', 'MONITOR'),
('P0115', 'Circuito del Sensor ECT', 'Mal funcionamiento del circuito del sensor de temperatura del refrigerante.', 'ENGINE', 'MODERATE', 'Revisar cableado, conector y sensor ECT. Verificar nivel de refrigerante.', 'CAUTION'),
('P0116', 'Rango/Rendimiento del Sensor ECT', 'El sensor de temperatura del refrigerante muestra valores fuera de rango.', 'ENGINE', 'MODERATE', 'Revisar termostato, sensor ECT y sistema de enfriamiento.', 'CAUTION'),
('P0117', 'Sensor ECT - Entrada Baja', 'Señal baja del sensor de temperatura del refrigerante del motor.', 'ENGINE', 'MODERATE', 'Verificar cableado del sensor ECT, posible cortocircuito a tierra.', 'CAUTION'),
('P0118', 'Sensor ECT - Entrada Alta', 'Señal alta del sensor de temperatura del refrigerante del motor.', 'ENGINE', 'MODERATE', 'Verificar conector y cableado del sensor ECT, posible circuito abierto.', 'CAUTION'),
('P0120', 'Circuito del Sensor TPS', 'Mal funcionamiento del sensor de posición del acelerador.', 'ENGINE', 'MODERATE', 'Revisar sensor TPS, cableado y conector. Reemplazar si es necesario.', 'CAUTION'),
('P0121', 'Rango/Rendimiento del Sensor TPS', 'El sensor de posición del acelerador muestra valores inconsistentes.', 'ENGINE', 'MODERATE', 'Limpiar cuerpo de aceleración, revisar sensor TPS y cableado.', 'CAUTION'),
('P0122', 'Sensor TPS - Entrada Baja', 'Señal baja del sensor de posición del acelerador.', 'ENGINE', 'MODERATE', 'Verificar conector y cableado del TPS. Posible corto a tierra.', 'CAUTION'),
('P0125', 'Temperatura Insuficiente para Control de Combustible', 'El motor no alcanza temperatura operativa en tiempo esperado.', 'ENGINE', 'LOW', 'Revisar termostato (probablemente atascado abierto), sensor ECT.', 'MONITOR'),
('P0128', 'Termostato - Temperatura por Debajo del Rango', 'El refrigerante no alcanza la temperatura de operación.', 'ENGINE', 'LOW', 'Reemplazar termostato. Verificar que no esté atascado abierto.', 'MONITOR'),
('P0130', 'Circuito del Sensor O2 (Banco 1, Sensor 1)', 'Mal funcionamiento del sensor de oxígeno upstream banco 1.', 'ENGINE', 'MODERATE', 'Revisar sensor O2, cableado y conector. Verificar fugas de escape.', 'CAUTION'),
('P0131', 'Sensor O2 Bajo Voltaje (B1S1)', 'Voltaje bajo en el sensor de oxígeno banco 1, sensor 1.', 'ENGINE', 'MODERATE', 'Verificar fugas de vacío, presión de combustible y sensor O2.', 'CAUTION'),
('P0132', 'Sensor O2 Alto Voltaje (B1S1)', 'Voltaje alto en el sensor de oxígeno banco 1, sensor 1.', 'ENGINE', 'MODERATE', 'Verificar inyectores con fuga, regulador de presión y sensor O2.', 'CAUTION'),
('P0133', 'Respuesta Lenta del Sensor O2 (B1S1)', 'El sensor de oxígeno tarda demasiado en cambiar entre rico y pobre.', 'ENGINE', 'MODERATE', 'Reemplazar sensor O2. Verificar posibles fugas de escape.', 'CAUTION'),
('P0134', 'Sin Actividad del Sensor O2 (B1S1)', 'No se detecta actividad en el sensor de oxígeno banco 1, sensor 1.', 'ENGINE', 'MODERATE', 'Verificar cableado del calentador del sensor O2, reemplazar sensor.', 'CAUTION'),
('P0135', 'Circuito del Calentador del Sensor O2 (B1S1)', 'Falla en el circuito del calentador del sensor de oxígeno.', 'ENGINE', 'LOW', 'Revisar fusible del calentador, cableado y reemplazar sensor O2 si es necesario.', 'MONITOR'),
('P0136', 'Circuito del Sensor O2 (Banco 1, Sensor 2)', 'Mal funcionamiento del sensor de oxígeno downstream banco 1.', 'ENGINE', 'MODERATE', 'Revisar sensor O2 downstream, cableado y conectores.', 'CAUTION'),
('P0141', 'Circuito del Calentador del Sensor O2 (B1S2)', 'Falla en el calentador del sensor de oxígeno downstream banco 1.', 'ENGINE', 'LOW', 'Verificar fusible, cableado y reemplazar sensor O2 si es necesario.', 'MONITOR'),
('P0150', 'Circuito del Sensor O2 (Banco 2, Sensor 1)', 'Mal funcionamiento del sensor de oxígeno upstream banco 2.', 'ENGINE', 'MODERATE', 'Revisar sensor O2 banco 2, cableado y conector.', 'CAUTION'),
('P0155', 'Circuito del Calentador del Sensor O2 (B2S1)', 'Falla en el calentador del sensor de oxígeno banco 2, sensor 1.', 'ENGINE', 'LOW', 'Revisar fusible, cableado y sensor O2 banco 2.', 'MONITOR'),
('P0170', 'Ajuste de Combustible (Banco 1)', 'Mal funcionamiento del ajuste de combustible del banco 1.', 'ENGINE', 'MODERATE', 'Revisar fugas de vacío, inyectores, sensor MAF y presión de combustible.', 'CAUTION'),
('P0171', 'Sistema Demasiado Pobre (Banco 1)', 'El motor recibe demasiado aire o poco combustible en el banco 1.', 'ENGINE', 'MODERATE', 'Revisar sensor MAF, fugas de vacío, bomba de combustible, filtro de combustible e inyectores.', 'CAUTION'),
('P0172', 'Sistema Demasiado Rico (Banco 1)', 'El motor recibe demasiado combustible o poco aire en el banco 1.', 'ENGINE', 'MODERATE', 'Revisar inyectores con fuga, regulador de presión, sensor MAF y filtro de aire.', 'CAUTION'),
('P0174', 'Sistema Demasiado Pobre (Banco 2)', 'El motor recibe demasiado aire o poco combustible en el banco 2.', 'ENGINE', 'MODERATE', 'Revisar fugas de vacío en banco 2, sensor MAF, bomba e inyectores.', 'CAUTION'),
('P0175', 'Sistema Demasiado Rico (Banco 2)', 'El motor recibe demasiado combustible en el banco 2.', 'ENGINE', 'MODERATE', 'Revisar inyectores, regulador de presión, sensor O2 banco 2.', 'CAUTION'),
('P0190', 'Circuito del Sensor de Presión del Riel de Combustible', 'Señal errónea del sensor de presión del riel de combustible.', 'ENGINE', 'HIGH', 'Revisar sensor de presión del riel, cableado y presión de combustible real.', 'STOP_DRIVING'),
('P0200', 'Circuito del Inyector - Mal Funcionamiento', 'Falla general en el circuito de control de inyectores.', 'ENGINE', 'HIGH', 'Revisar cableado de inyectores, conectores y módulo de control (ECM).', 'STOP_DRIVING'),
('P0201', 'Circuito del Inyector - Cilindro 1', 'Falla en el circuito del inyector del cilindro 1.', 'ENGINE', 'HIGH', 'Revisar cableado y conector del inyector 1, medir resistencia del inyector.', 'STOP_DRIVING'),
('P0202', 'Circuito del Inyector - Cilindro 2', 'Falla en el circuito del inyector del cilindro 2.', 'ENGINE', 'HIGH', 'Revisar cableado y conector del inyector 2, medir resistencia del inyector.', 'STOP_DRIVING'),
('P0203', 'Circuito del Inyector - Cilindro 3', 'Falla en el circuito del inyector del cilindro 3.', 'ENGINE', 'HIGH', 'Revisar cableado y conector del inyector 3, medir resistencia del inyector.', 'STOP_DRIVING'),
('P0204', 'Circuito del Inyector - Cilindro 4', 'Falla en el circuito del inyector del cilindro 4.', 'ENGINE', 'HIGH', 'Revisar cableado y conector del inyector 4, medir resistencia del inyector.', 'STOP_DRIVING'),
('P0217', 'Sobrecalentamiento del Motor', 'La temperatura del motor ha excedido el límite seguro.', 'ENGINE', 'HIGH', 'DETENER inmediatamente. Revisar nivel de refrigerante, termostato, bomba de agua y radiador.', 'STOP_DRIVING'),
('P0218', 'Sobrecalentamiento de la Transmisión', 'El fluido de la transmisión ha excedido la temperatura segura.', 'ENGINE', 'HIGH', 'Detener y dejar enfriar. Revisar nivel de fluido ATF, enfriador de transmisión.', 'STOP_DRIVING'),
('P0219', 'Sobre-Revolución del Motor', 'Las RPM del motor han excedido el límite programado.', 'ENGINE', 'HIGH', 'Verificar sensor de velocidad del motor, cables de acelerador y módulo ECM.', 'STOP_DRIVING'),
('P0220', 'Circuito del Sensor TPS B', 'Mal funcionamiento del sensor de posición del acelerador secundario.', 'ENGINE', 'MODERATE', 'Revisar cuerpo de aceleración electrónico, sensor TPS B y cableado.', 'CAUTION'),
('P0230', 'Circuito de la Bomba de Combustible', 'Mal funcionamiento del circuito primario de la bomba de combustible.', 'ENGINE', 'HIGH', 'Revisar relé de bomba de combustible, fusible, cableado y bomba.', 'STOP_DRIVING'),
('P0261', 'Inyector Cilindro 1 - Circuito Bajo', 'Señal baja en el circuito del inyector del cilindro 1.', 'ENGINE', 'HIGH', 'Verificar cableado del inyector 1, posible cortocircuito a tierra.', 'STOP_DRIVING'),
('P0300', 'Fallo de Encendido Aleatorio/Múltiple (Misfire)', 'Fallas de combustión irregulares no fijas a un solo cilindro.', 'ENGINE', 'HIGH', 'Revisar fugas de vacío (intake), presión baja de combustible, válvula EGR, o gasolina contaminada.', 'STOP_DRIVING'),
('P0301', 'Fallo de Encendido - Cilindro 1', 'Se detecta fallo de encendido específico en el cilindro 1.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 1. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0302', 'Fallo de Encendido - Cilindro 2', 'Se detecta fallo de encendido específico en el cilindro 2.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 2. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0303', 'Fallo de Encendido - Cilindro 3', 'Se detecta fallo de encendido específico en el cilindro 3.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 3. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0304', 'Fallo de Encendido - Cilindro 4', 'Se detecta fallo de encendido específico en el cilindro 4.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 4. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0305', 'Fallo de Encendido - Cilindro 5', 'Se detecta fallo de encendido específico en el cilindro 5.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 5. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0306', 'Fallo de Encendido - Cilindro 6', 'Se detecta fallo de encendido específico en el cilindro 6.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 6. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0307', 'Fallo de Encendido - Cilindro 7', 'Se detecta fallo de encendido específico en el cilindro 7.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 7. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0308', 'Fallo de Encendido - Cilindro 8', 'Se detecta fallo de encendido específico en el cilindro 8.', 'ENGINE', 'HIGH', 'Revisar bujía, bobina/cable del cilindro 8. Verificar compresión e inyector.', 'STOP_DRIVING'),
('P0325', 'Circuito del Sensor de Detonación (Banco 1)', 'Mal funcionamiento del sensor de detonación (knock sensor) del banco 1.', 'ENGINE', 'MODERATE', 'Revisar sensor de detonación, cableado y conector. Reemplazar si es necesario.', 'CAUTION'),
('P0327', 'Sensor de Detonación - Entrada Baja (B1)', 'Señal baja del sensor knock banco 1.', 'ENGINE', 'MODERATE', 'Verificar torque del sensor, cableado y reemplazar si es necesario.', 'CAUTION'),
('P0330', 'Circuito del Sensor de Detonación (Banco 2)', 'Mal funcionamiento del sensor de detonación del banco 2.', 'ENGINE', 'MODERATE', 'Revisar sensor de detonación banco 2, cableado y conector.', 'CAUTION'),
('P0335', 'Sensor de Posición del Cigüeñal (CKP)', 'No se recibe señal del sensor de posición del cigüeñal.', 'ENGINE', 'HIGH', 'Revisar sensor CKP, cableado, conector y rueda reluctora. El motor puede no arrancar.', 'STOP_DRIVING'),
('P0336', 'Rango/Rendimiento del Sensor CKP', 'El sensor del cigüeñal envía señal irregular o fuera de rango.', 'ENGINE', 'HIGH', 'Verificar espacio entre sensor y rueda reluctora, limpiar o reemplazar sensor CKP.', 'STOP_DRIVING'),
('P0340', 'Sensor de Posición del Árbol de Levas (CMP)', 'No se recibe señal del sensor de posición del árbol de levas.', 'ENGINE', 'HIGH', 'Revisar sensor CMP, cableado, conector y correa/cadena de distribución.', 'STOP_DRIVING'),
('P0341', 'Rango/Rendimiento del Sensor CMP', 'Señal fuera de rango del sensor del árbol de levas.', 'ENGINE', 'HIGH', 'Verificar distribución, sensor CMP y cableado.', 'STOP_DRIVING'),
('P0350', 'Circuito de Bobina de Encendido', 'Mal funcionamiento en el circuito primario/secundario de la bobina de encendido.', 'ENGINE', 'HIGH', 'Revisar bobinas de encendido, cableado y módulo de encendido.', 'STOP_DRIVING'),
('P0400', 'Flujo de Recirculación de Gases de Escape (EGR)', 'Mal funcionamiento del flujo del sistema EGR.', 'ENGINE', 'MODERATE', 'Limpiar o reemplazar válvula EGR, revisar conductos y sensor de posición.', 'CAUTION'),
('P0401', 'Flujo EGR Insuficiente', 'El flujo de gases recirculados es menor al esperado.', 'ENGINE', 'MODERATE', 'Limpiar válvula EGR y conductos de carbón. Verificar sensor de presión diferencial.', 'CAUTION'),
('P0402', 'Flujo EGR Excesivo', 'El flujo de gases recirculados es mayor al esperado.', 'ENGINE', 'MODERATE', 'Revisar válvula EGR (posiblemente atascada abierta), limpiar o reemplazar.', 'CAUTION'),
('P0410', 'Sistema de Inyección de Aire Secundario', 'Mal funcionamiento del sistema de inyección de aire secundario.', 'ENGINE', 'LOW', 'Revisar bomba de aire secundario, válvula check y cableado del relé.', 'MONITOR'),
('P0411', 'Flujo Incorrecto del Sistema de Aire Secundario', 'El sistema de aire secundario no inyecta el flujo correcto.', 'ENGINE', 'LOW', 'Verificar bomba de aire, mangueras y válvula de control.', 'MONITOR'),
('P0420', 'Eficiencia del Sistema de Catalizador por Debajo del Umbral (Banco 1)', 'El convertidor catalítico lado cilindro 1 no está purificando gases correctamente.', 'ENGINE', 'MODERATE', 'Verificar que no haya fallas de encendido. Si el motor está perfecto, reemplazar catalizador.', 'CAUTION'),
('P0421', 'Eficiencia de Calentamiento del Catalizador (Banco 1)', 'El catalizador no alcanza temperatura operativa a tiempo.', 'ENGINE', 'MODERATE', 'Revisar sensor O2 upstream, fugas de escape y catalizador.', 'CAUTION'),
('P0430', 'Eficiencia del Sistema de Catalizador por Debajo del Umbral (Banco 2)', 'El convertidor catalítico del segundo banco no está purificando gases.', 'ENGINE', 'MODERATE', 'Confirmar gráfica del sensor O2 post-catalizador. Reemplazar catalizador B2.', 'CAUTION'),
('P0440', 'Sistema de Emisión Evaporativa (EVAP)', 'Mal funcionamiento general del sistema EVAP.', 'ENGINE', 'LOW', 'Revisar tapa de combustible, mangueras EVAP, válvula de purga y canister.', 'MONITOR'),
('P0441', 'Flujo Incorrecto de Purga EVAP', 'El flujo de purga del sistema EVAP no es el esperado.', 'ENGINE', 'LOW', 'Revisar válvula de purga, mangueras y canister de carbón activado.', 'MONITOR'),
('P0442', 'Fuga Pequeña en Sistema EVAP', 'Fuga pequeña detectada en el sistema de emisiones evaporativas.', 'ENGINE', 'LOW', 'Verificar tapa de combustible, mangueras y conexiones del sistema EVAP.', 'MONITOR'),
('P0443', 'Circuito de Válvula de Purga EVAP', 'Mal funcionamiento del circuito de la válvula de purga.', 'ENGINE', 'LOW', 'Revisar válvula de purga, cableado y conector eléctrico.', 'MONITOR'),
('P0446', 'Circuito de Ventilación EVAP', 'Mal funcionamiento del circuito de control de ventilación del sistema EVAP.', 'ENGINE', 'LOW', 'Revisar válvula de ventilación del canister, cableado y filtro.', 'MONITOR'),
('P0449', 'Circuito de Válvula de Ventilación EVAP', 'Falla en el solenoide de ventilación del canister.', 'ENGINE', 'LOW', 'Revisar solenoide de ventilación, cableado y conector.', 'MONITOR'),
('P0455', 'Fuga Grande en Sistema EVAP', 'Se detectó una fuga grande en el sistema de emisiones evaporativas.', 'ENGINE', 'LOW', 'Verificar tapa de combustible (apretar o reemplazar), mangueras rotas o desconectadas del sistema EVAP.', 'MONITOR'),
('P0456', 'Fuga Muy Pequeña Sistema EVAP (0.020") (FCA)', 'Micro fuga detectada en sistema de control de emisiones.', 'ENGINE', 'LOW', 'Cambiar tapa de tanque, revisar sello de bomba NVLD/ESIM.', 'MONITOR'),
('P0460', 'Circuito del Sensor de Nivel de Combustible', 'Mal funcionamiento del circuito del sensor de nivel de combustible.', 'ENGINE', 'LOW', 'Revisar sensor de nivel en el tanque, cableado y conector.', 'MONITOR'),
('P0480', 'Circuito de Control del Ventilador 1', 'Mal funcionamiento del circuito del ventilador del radiador.', 'ENGINE', 'MODERATE', 'Revisar relé del ventilador, fusible, motor del ventilador y cableado.', 'CAUTION'),
('P0500', 'Sensor de Velocidad del Vehículo (VSS)', 'No se recibe señal del sensor de velocidad del vehículo.', 'ENGINE', 'MODERATE', 'Revisar sensor VSS, cableado, conector y engranajes del sensor.', 'CAUTION'),
('P0505', 'Sistema de Control de Ralentí (IAC)', 'Mal funcionamiento del sistema de control de velocidad de ralentí.', 'ENGINE', 'MODERATE', 'Limpiar válvula IAC, cuerpo de aceleración. Revisar fugas de vacío.', 'CAUTION'),
('P0506', 'RPM de Ralentí Bajas', 'La velocidad de ralentí es menor a la esperada por la ECU.', 'ENGINE', 'LOW', 'Limpiar cuerpo de aceleración y válvula IAC. Revisar fugas de vacío.', 'MONITOR'),
('P0507', 'RPM de Ralentí Altas', 'La velocidad de ralentí es mayor a la esperada por la ECU.', 'ENGINE', 'LOW', 'Revisar fugas de vacío, válvula IAC, cuerpo de aceleración y sensores TPS.', 'MONITOR'),
('P0510', 'Sensor de Posición de Mariposa Cerrada', 'Mal funcionamiento del switch de posición cerrada del acelerador.', 'ENGINE', 'LOW', 'Ajustar o reemplazar switch de mariposa cerrada, revisar cableado.', 'MONITOR'),
('P0520', 'Circuito del Sensor de Presión de Aceite', 'Mal funcionamiento del circuito del sensor/switch de presión de aceite.', 'ENGINE', 'MODERATE', 'Revisar nivel de aceite, sensor de presión, cableado y conector.', 'CAUTION'),
('P0521', 'Rango/Rendimiento del Sensor de Presión de Aceite', 'El sensor de presión de aceite reporta valores fuera de rango.', 'ENGINE', 'MODERATE', 'Verificar presión real con manómetro, reemplazar sensor si da lecturas erróneas.', 'CAUTION'),
('P0524', 'Presión de Aceite Demasiado Baja', 'La presión de aceite del motor está por debajo del mínimo seguro.', 'ENGINE', 'HIGH', 'DETENER el motor. Verificar nivel de aceite, bomba de aceite y posibles fugas.', 'STOP_DRIVING'),
('P0530', 'Circuito del Sensor de Presión del A/C', 'Mal funcionamiento del circuito del sensor de presión del refrigerante A/C.', 'ENGINE', 'LOW', 'Revisar carga de refrigerante, sensor de presión y cableado.', 'MONITOR'),
('P0550', 'Circuito del Sensor de Dirección Asistida', 'Mal funcionamiento del circuito del sensor de presión de dirección asistida.', 'ENGINE', 'LOW', 'Revisar nivel de fluido, sensor de presión y cableado.', 'MONITOR'),
('P0560', 'Voltaje del Sistema Eléctrico', 'Voltaje del sistema fuera del rango normal.', 'ENGINE', 'MODERATE', 'Revisar batería, alternador, cables y conexiones a tierra.', 'CAUTION'),
('P0562', 'Voltaje del Sistema Bajo', 'El voltaje del sistema eléctrico es menor al esperado.', 'ENGINE', 'MODERATE', 'Verificar batería, alternador, correa y conexiones eléctricas.', 'CAUTION'),
('P0563', 'Voltaje del Sistema Alto', 'El voltaje del sistema eléctrico es mayor al esperado.', 'ENGINE', 'MODERATE', 'Verificar regulador de voltaje del alternador, batería.', 'CAUTION'),
('P0600', 'Error de Comunicación Serial (CAN Bus)', 'Error de comunicación interna en el módulo de control del motor.', 'ENGINE', 'HIGH', 'Verificar alimentación de la ECU, conexiones a tierra y bus CAN.', 'STOP_DRIVING'),
('P0601', 'Error de Memoria Interna del ECM (ROM)', 'Error de checksum en la memoria del módulo de control del motor.', 'ENGINE', 'HIGH', 'Reprogramar o reemplazar ECM. Verificar alimentación eléctrica.', 'STOP_DRIVING'),
('P0602', 'Error de Programación del ECM', 'El módulo de control necesita ser reprogramado.', 'ENGINE', 'HIGH', 'Reprogramar ECM con software actualizado del fabricante.', 'STOP_DRIVING'),
('P0603', 'Error de Memoria KAM del ECM', 'Error en la memoria de aprendizaje adaptativo del ECM.', 'ENGINE', 'MODERATE', 'Desconectar batería 30 min para resetear. Si persiste, reemplazar ECM.', 'CAUTION'),
('P0606', 'Error del Procesador del ECM', 'Falla interna del procesador del módulo de control del motor.', 'ENGINE', 'HIGH', 'Reemplazar ECM. Verificar arnés de cableado y alimentación.', 'STOP_DRIVING'),
('P0615', 'Circuito del Relé del Motor de Arranque', 'Mal funcionamiento del circuito del relé de arranque.', 'ENGINE', 'MODERATE', 'Revisar relé de arranque, fusible, cableado y motor de arranque.', 'CAUTION'),
('P0627', 'Circuito de Control de la Bomba de Combustible', 'Falla en el circuito de control de la bomba de combustible.', 'ENGINE', 'HIGH', 'Revisar relé, fusible y cableado de la bomba de combustible.', 'STOP_DRIVING'),
('P0650', 'Circuito del Indicador MIL (Check Engine)', 'Falla en el circuito de la luz indicadora de falla (MIL).', 'ENGINE', 'LOW', 'Revisar bombillo MIL, cableado del tablero y conector.', 'MONITOR'),
('P0700', 'Mal Funcionamiento del Control de Transmisión', 'Se detectó falla general en el sistema de control de la transmisión automática.', 'TRANSMISSION', 'HIGH', 'Leer códigos específicos del módulo TCM con escáner avanzado. Revisar nivel de ATF.', 'STOP_DRIVING')
INSERT INTO public.dtc_codes (code, description_es, description_en, system, severity, possible_causes, urgency) VALUES 
('P0705', 'Circuito del Sensor de Rango de Transmisión', 'Señal errónea del sensor de posición del selector (PRNDL).', 'TRANSMISSION', 'MODERATE', 'Ajustar o reemplazar sensor de rango, revisar cableado y conector.', 'CAUTION'),
('P0710', 'Circuito del Sensor de Temperatura de Transmisión', 'Mal funcionamiento del sensor de temperatura del fluido de transmisión.', 'TRANSMISSION', 'MODERATE', 'Revisar sensor TFT, cableado y nivel/condición del fluido ATF.', 'CAUTION'),
('P0715', 'Sensor de Velocidad de Entrada de Transmisión', 'No se recibe señal del sensor de velocidad de entrada (turbina).', 'TRANSMISSION', 'HIGH', 'Revisar sensor de velocidad de turbina, cableado y conector.', 'STOP_DRIVING'),
('P0720', 'Sensor de Velocidad de Salida de Transmisión', 'Mal funcionamiento del sensor de velocidad de salida de la transmisión.', 'TRANSMISSION', 'HIGH', 'Revisar sensor de velocidad de salida, cableado y conector.', 'STOP_DRIVING'),
