('P2459', 'Frecuencia de Regeneración del DPF', 'Las regeneraciones del DPF ocurren con demasiada frecuencia.', 'ENGINE', 'MODERATE', 'Revisar inyectores (posible exceso de hollín), sensor de presión del DPF.', 'CAUTION'),
('P2463', 'Acumulación Excesiva de Hollín en DPF', 'El filtro de partículas tiene una acumulación de hollín por encima del límite.', 'ENGINE', 'HIGH', 'Realizar regeneración forzada. Si no funciona, limpieza profesional del DPF.', 'STOP_DRIVING'),
('B0010', 'Circuito del Airbag Lateral Izquierdo', 'Falla en el circuito del airbag lateral del conductor.', 'BODY', 'HIGH', 'Revisar cableado del airbag lateral, conector y módulo SRS.', 'STOP_DRIVING'),
('B0011', 'Circuito del Airbag Lateral Derecho', 'Falla en el circuito del airbag lateral del pasajero.', 'BODY', 'HIGH', 'Revisar cableado del airbag lateral derecho y módulo SRS.', 'STOP_DRIVING'),
('B0020', 'Circuito del Airbag de Cortina Izquierdo', 'Falla en el circuito del airbag de cortina del lado del conductor.', 'BODY', 'HIGH', 'Revisar cableado de la cortina de aire, conectores y módulo SRS.', 'STOP_DRIVING'),
('B0021', 'Circuito del Airbag de Cortina Derecho', 'Falla en el circuito del airbag de cortina del lado del pasajero.', 'BODY', 'HIGH', 'Revisar cableado de la cortina de aire derecha y módulo SRS.', 'STOP_DRIVING'),
('B0050', 'Sensor de Impacto Frontal Izquierdo', 'Falla en el sensor de impacto frontal del lado del conductor.', 'BODY', 'HIGH', 'Revisar sensor de impacto, cableado y conector.', 'STOP_DRIVING'),
('B0051', 'Sensor de Impacto Frontal Derecho', 'Falla en el sensor de impacto frontal del lado del pasajero.', 'BODY', 'HIGH', 'Revisar sensor de impacto derecho, cableado y conector.', 'STOP_DRIVING'),
('B0060', 'Sensor de Impacto Lateral Izquierdo', 'Falla en el sensor de impacto lateral del conductor.', 'BODY', 'HIGH', 'Revisar sensor de impacto lateral, cableado y módulo SRS.', 'STOP_DRIVING'),
('B0100', 'Voltaje de Alimentación del Módulo SRS', 'Voltaje fuera de rango en el módulo de airbags.', 'BODY', 'HIGH', 'Verificar batería, cableado de alimentación del módulo SRS y tierras.', 'STOP_DRIVING'),
('C0060', 'Circuito del Motor de la Bomba ABS', 'Falla en el motor de la bomba del sistema de frenos ABS.', 'CHASSIS', 'HIGH', 'Revisar relé de la bomba ABS, motor de bomba, fusible y cableado.', 'STOP_DRIVING'),
('C0065', 'Relé de la Bomba ABS', 'Falla en el relé que controla la bomba del ABS.', 'CHASSIS', 'HIGH', 'Reemplazar relé de la bomba ABS, verificar cableado.', 'STOP_DRIVING'),
('C0070', 'Válvula Solenoide de Freno ABS', 'Falla en una de las válvulas solenoides del módulo ABS.', 'CHASSIS', 'HIGH', 'Posible reemplazo del módulo hidráulico ABS completo.', 'STOP_DRIVING'),
('C0110', 'Circuito del Motor de la Bomba de Control de Estabilidad', 'Falla en el motor de la bomba del sistema ESP/ESC.', 'CHASSIS', 'HIGH', 'Revisar motor de bomba ESP, relé, fusible y cableado.', 'STOP_DRIVING'),
('C0300', 'Sensor del Ángulo de Dirección', 'Mal funcionamiento del sensor de ángulo del volante.', 'CHASSIS', 'MODERATE', 'Calibrar sensor de ángulo de dirección con escáner. Reemplazar si falla.', 'CAUTION'),
('C0455', 'Sensor de Velocidad de Giro (Yaw Rate)', 'Falla en el sensor de velocidad de giro del sistema ESP.', 'CHASSIS', 'MODERATE', 'Revisar sensor de giro, cableado y calibración del módulo ESP.', 'CAUTION'),
('C0460', 'Sensor de Aceleración Lateral', 'Falla en el sensor de aceleración lateral del sistema de estabilidad.', 'CHASSIS', 'MODERATE', 'Revisar sensor de aceleración lateral, cableado y módulo ESP.', 'CAUTION'),
('C0561', 'Sistema de Control de Estabilidad Deshabilitado', 'El sistema ESP/ESC se ha deshabilitado por una falla detectada.', 'CHASSIS', 'MODERATE', 'Diagnosticar código primario que causó la desactivación del ESP.', 'CAUTION'),
('C0710', 'Circuito del Sensor de Dirección Asistida Eléctrica', 'Falla en el sistema de dirección asistida eléctrica (EPS).', 'CHASSIS', 'HIGH', 'Revisar motor EPS, sensor de torque, cableado y módulo de control.', 'STOP_DRIVING'),
('C0800', 'Voltaje del Sistema de Frenos de Potencia', 'Voltaje fuera de rango en el sistema de frenos eléctricos.', 'CHASSIS', 'HIGH', 'Verificar batería, alternador y cableado del módulo de frenos.', 'STOP_DRIVING'),
('P0A00', 'Circuito del Sensor de Temperatura del Refrigerante del Motor Eléctrico', 'Falla en el circuito del sensor de temperatura del inversor/motor eléctrico.', 'HYBRID', 'MODERATE', 'Revisar sensor de temperatura del inversor, bomba de agua eléctrica y nivel de refrigerante HEV.', 'CAUTION'),
('P0A08', 'Fallo del Circuito del Convertidor DC/DC', 'Problema en el convertidor de alta tensión a 12V.', 'HYBRID', 'HIGH', 'Verificar alimentación de alta tensión, fusibles principales y convertidor DC/DC.', 'STOP_DRIVING'),
('P0A09', 'Circuito del Convertidor DC/DC Bajo', 'Señal baja en el circuito de estado del convertidor DC/DC.', 'HYBRID', 'HIGH', 'Revisar conexiones del convertidor DC/DC, estado de la batería de 12V.', 'STOP_DRIVING'),
('P0A78', 'Rendimiento del Inversor del Motor de Tracción', 'Mal funcionamiento interno en el inversor del motor eléctrico.', 'HYBRID', 'HIGH', 'Verificar cableado de alta tensión (NARANJA - PELIGRO), módulo inversor. Requiere técnico especializado en HV.', 'STOP_DRIVING'),
('P0A79', 'Rendimiento del Inversor del Generador', 'Falla en el inversor del motor-generador (MG1).', 'HYBRID', 'HIGH', 'Verificar módulo inversor/conversor. Aislar sistema HV antes de intervenir.', 'STOP_DRIVING'),
('P0A80', 'Reemplazar Paquete de Baterías Híbridas', 'Degradación crítica detectada en los módulos de la batería de alto voltaje.', 'HYBRID', 'HIGH', 'Balancear o reemplazar módulos dañados de la batería HV, o reemplazar paquete completo.', 'STOP_DRIVING'),
('P0A81', 'Circuito del Ventilador de la Batería Híbrida', 'Falla en el sistema de enfriamiento de la batería de alto voltaje.', 'HYBRID', 'MODERATE', 'Limpiar conductos y ventilador de la batería, revisar motor del ventilador.', 'CAUTION'),
('P0A93', 'Rendimiento del Sistema de Enfriamiento del Inversor', 'Sobrecalentamiento del sistema inversor/conversor.', 'HYBRID', 'HIGH', 'Verificar bomba de agua del inversor, nivel de refrigerante específico para HEV.', 'STOP_DRIVING'),
('P0A94', 'Rendimiento del Convertidor DC/DC', 'Falla general en la conversión de voltaje HV a 12V.', 'HYBRID', 'HIGH', 'Reemplazar conjunto inversor/convertidor. Revisar cableado HV.', 'STOP_DRIVING'),
('P0AA6', 'Aislamiento de Alto Voltaje Defectuoso', 'Fuga de corriente de alto voltaje hacia el chasis detectada.', 'HYBRID', 'HIGH', '¡PELIGRO! Riesgo de electrocución. Buscar daño en cables naranjas, motor MG1/MG2 o inversor.', 'STOP_DRIVING'),
('P0AC4', 'Módulo de Control Híbrido Solicitó Encender MIL', 'El módulo HEV/EV pide a la ECU del motor encender la luz de falla.', 'HYBRID', 'MODERATE', 'Escanear módulo HEV para obtener códigos específicos de la falla híbrida.', 'CAUTION'),
('P0032', 'Calentador Sensor O2 - Alto (B1S1) (Nissan)', 'Cortocircuito a voltaje en el calentador del sensor O2.', 'ENGINE', 'MODERATE', 'Verificar mazo de cables del sensor O2, posible cruce con cables de alimentación.', 'CAUTION'),
('P1111', 'Circuito del Solenoide VVT de Admisión (Nissan)', 'Falla en el sistema de control de válvulas IVT de Nissan.', 'ENGINE', 'MODERATE', 'Limpiar solenoide IVT, revisar nivel y presión de aceite.', 'CAUTION'),
('P1148', 'Control de Lazo Cerrado del Sensor O2 (Nissan)', 'Falla en el control de mezcla cerrada del banco 1.', 'ENGINE', 'MODERATE', 'Verificar sensor de relación aire-combustible (A/F) y cableado.', 'CAUTION'),
('P1564', 'Switch de Control de Crucero en Volante (Nissan)', 'Falla en el circuito del switch (ASCD) en el volante.', 'ENGINE', 'LOW', 'Revisar conector espiral (clockspring) y switches del volante.', 'MONITOR'),
('P1705', 'Sensor de Posición del Acelerador para TCM (Nissan)', 'La transmisión no recibe señal correcta del TPS.', 'ENGINE', 'HIGH', 'Verificar sensor TPS, cableado entre ECM y TCM.', 'STOP_DRIVING'),
('P1050', 'Control VVT - Exceso de Corriente (BMW Valvetronic)', 'El motor Valvetronic consume demasiada corriente.', 'ENGINE', 'HIGH', 'Revisar motor Valvetronic, eje excéntrico y sensor de posición.', 'STOP_DRIVING'),
('P105D', 'Ajuste Valvetronic - Límite Alcanzado (BMW)', 'El sistema Valvetronic no puede alcanzar la posición comandada.', 'ENGINE', 'HIGH', 'Realizar calibración Valvetronic. Revisar desgaste en eje excéntrico.', 'STOP_DRIVING'),
