('P1539', 'Clutch del A/C - Exceso de Corriente / Falla (VAG)', 'Falla en el circuito del embrague magnético del compresor A/C.', 'ENGINE', 'LOW', 'Revisar bobina del compresor, fusible y relé del A/C.', 'MONITOR'),
('U1000', 'Falla de Red Clase 2 (GM) / CAN Comunicación (Nissan)', 'Falla genérica de comunicación en la red principal.', 'NETWORK', 'HIGH', 'Verificar empalmes de tierra, humedad en módulos y terminales del conector OBD2.', 'STOP_DRIVING'),
('P1296', 'Mal Funcionamiento en Sistema de Enfriamiento (VAG)', 'Falla en el sensor de temperatura del refrigerante o termostato (falla muy común en motores 1.8T).', 'ENGINE', 'MODERATE', 'Reemplazar sensor de temperatura del refrigerante (sensor verde) y revisar termostato.', 'CAUTION'),
('P2181', 'Rendimiento del Sistema de Enfriamiento (VAG)', 'El motor no alcanza la temperatura de operación correcta.', 'ENGINE', 'MODERATE', 'Reemplazar termostato y sensor G62. Verificar nivel de anticongelante G12/G13.', 'CAUTION'),
('P3081', 'Temperatura del Motor Muy Baja (VAG)', 'El sensor de temperatura indica que el motor no calienta.', 'ENGINE', 'MODERATE', 'Revisar sensor de temperatura G62 y termostato abierto.', 'CAUTION'),
('P1545', 'Mal Funcionamiento Cuerpo de Aceleración (VAG)', 'Error de control de la mariposa electrónica.', 'ENGINE', 'HIGH', 'Limpiar cuerpo de aceleración y realizar alineación básica (Throttle Body Alignment) con escáner.', 'STOP_DRIVING'),
('P1602', 'Corte de Tensión Borne 30 (VAG)', 'Interrupción de suministro de energía por voltaje bajo (batería desconectada).', 'ENGINE', 'LOW', 'Borrar código. Si regresa, revisar estado de la batería, bornes y alternador.', 'MONITOR'),
('P1326', 'Sensor de Detonación (Sistema KSDS - Hyundai/Kia)', 'El Sistema de Detección del Sensor Knock (KSDS) detectó vibraciones anormales (falla grave de motor).', 'ENGINE', 'HIGH', '¡DETENER MOTOR INMEDIATAMENTE! Posible desgaste severo de cojinetes de biela. Revisión bajo garantía.', 'STOP_DRIVING'),
