('P0191', 'Sensor de Presión de Riel de Combustible (Mazda)', 'Presión irregular en bomba de alta (HPFP) en motores Skyactiv GDI.', 'ENGINE', 'HIGH', 'Revisar bomba de alta presión de combustible, tapón en filtro.', 'STOP_DRIVING'),
('P061B', 'Cálculo de Torque del Módulo de Control Interno (Mazda)', 'Error interno en el cálculo de torque.', 'ENGINE', 'MODERATE', 'Limpiar sensor MAF, cuerpo de aceleración y revisar fugas de vacío.', 'CAUTION'),
('P3000', 'Sistema de Control de Batería HV', 'Falla genérica detectada por el módulo de la batería híbrida.', 'ENGINE', 'HIGH', 'Escanear módulo HV para leer submódulo y códigos detallados de voltaje.', 'STOP_DRIVING'),
