('P1009', 'Avance de Sincronización VTC Avanzado (Honda)', 'Sistema VTC atascado mecánicamente o actuador fallando.', 'ENGINE', 'HIGH', 'Revisar nivel de aceite, limpiar malla/filtro del actuador VTC.', 'STOP_DRIVING'),
('P1135', 'Circuito del Calentador A/F (B1S1) (Toyota)', 'Falla en el circuito del calentador del sensor Air/Fuel.', 'ENGINE', 'MODERATE', 'Revisar relé A/F, fusibles y reemplazar sensor A/F superior.', 'CAUTION'),
('P1258', 'Protección de Sobrecalentamiento Activa (GM)', 'El PCM alternará el disparo de inyectores para enfriar el motor.', 'ENGINE', 'HIGH', 'El motor está críticamente caliente. Apagar y revisar bomba de agua, radiador.', 'STOP_DRIVING'),
('P1443', 'Falla en la Válvula de Control de Purga EVAP (Ford)', 'La válvula termistor del EVAP no muestra voltaje correcto.', 'ENGINE', 'LOW', 'Reemplazar válvula de control de purga y sensor de flujo EVAP.', 'MONITOR'),
('P1633', 'Voltaje KAM Muy Bajo (Ford)', 'El voltaje de memoria Keep Alive (KAM) al PCM es muy bajo.', 'ENGINE', 'LOW', 'Revisar fusibles de KAM, batería y cableado hacia la computadora.', 'MONITOR'),
('U1001', 'Línea de Comunicación CAN (Nissan)', 'Error temporal o permanente de comunicación en la red CAN.', 'NETWORK', 'HIGH', 'Revisar conectores, daños físicos en cableado de red CAN y empalmes.', 'STOP_DRIVING'),
('U0122', 'Pérdida de Comunicación con el Módulo de Control de Dinámica (VDC/ESP)', 'Sin datos del módulo de control de tracción.', 'NETWORK', 'HIGH', 'Revisar módulo VDC, fusibles, red CAN.', 'STOP_DRIVING'),
('U1262', 'Fallo de Red de Comunicación SCP (Ford)', 'Error de la red estándar de Ford (SCP).', 'NETWORK', 'MODERATE', 'Verificar módulo de instrumentos y empalmes SCP.', 'CAUTION'),
('U1102', 'Tiempo de Espera de Datos ESP (Mitsubishi)', 'El módulo no recibe mensajes del control electrónico de estabilidad.', 'NETWORK', 'MODERATE', 'Verificar conexión y alimentación del módulo ESP/ABS.', 'CAUTION'),
('U0300', 'Incompatibilidad de Software del Módulo de Control Interno', 'Versión de software de módulo no coincide con el resto de la red.', 'NETWORK', 'HIGH', 'Actualizar firmware de los módulos a la versión compatible. Requiere escáner OEM.', 'STOP_DRIVING'),
('B2099', 'Alimentación Abierta Llave de Encendido', 'Circuito de retención del cilindro de llave con corto o abierto.', 'BODY', 'LOW', 'Revisar switch de ignición y módulo de la columna de dirección.', 'MONITOR'),
