('C1145', 'Falla del Sensor de Velocidad Rueda Delantera Derecha (Ford)', 'Pérdida de señal del sensor ABS delantero derecho.', 'CHASSIS', 'MODERATE', 'Revisar sensor, anillo reluctor o balero de rueda magnetizado.', 'CAUTION'),
('C1201', 'Sistema de Control del Motor (Toyota ABS)', 'El sistema ABS/VSC se desactiva porque hay una falla en el motor (Check Engine encendido).', 'CHASSIS', 'MODERATE', 'Este es un código reflejo. Escanear el motor y reparar el código P principal.', 'CAUTION'),
('C1231', 'Falla en el Sensor de Ángulo de Dirección', 'Pérdida del valor central del volante.', 'CHASSIS', 'MODERATE', 'Calibrar posición cero del sensor de ángulo de dirección (SAS).', 'CAUTION'),
('C2205', 'Error Interno del Sensor de Ángulo de Dirección', 'El sensor SAS ha fallado de forma interna.', 'CHASSIS', 'MODERATE', 'Reemplazar reloj espiral / sensor de ángulo de dirección.', 'CAUTION'),
('C1500', 'Torque Sensor EPS (Dirección Electrónica)', 'Falla en el sensor de torque de la dirección electroasistida.', 'CHASSIS', 'HIGH', 'Revisar columna de dirección o módulo EPS. No manipular sin desconectar batería.', 'STOP_DRIVING'),
('C0273', 'Falla en el Relé del Motor ABS (GM)', 'El relé principal del motor ABS no opera.', 'CHASSIS', 'HIGH', 'Revisar fusibles de alta corriente del ABS y módulo EBCM.', 'STOP_DRIVING'),
('P0313', 'Fallo de Encendido Detectado por Falta de Combustible', 'Misfire registrado debido a que el tanque está vacío o la presión es extremadamente baja.', 'ENGINE', 'HIGH', 'Llenar tanque, purgar sistema de combustible. Revisar presión de bomba.', 'STOP_DRIVING'),
('P0314', 'Fallo de Encendido de un Solo Cilindro (Cilindro No Especificado)', 'La ECU detecta misfire pero no puede aislar qué cilindro es.', 'ENGINE', 'HIGH', 'Realizar prueba de balance de cilindros con escáner avanzado.', 'STOP_DRIVING'),
('P00B7', 'Flujo Bajo de Refrigerante de Motor', 'Temperatura excesiva o circulación pobre detectada.', 'ENGINE', 'HIGH', 'Revisar nivel de refrigerante, bomba de agua y válvula termostática.', 'STOP_DRIVING'),
('P2007', 'Válvula de Control de Múltiple de Admisión (IMRC) Atrapada Abierta', 'Las aletas del múltiple de admisión se quedaron pegadas en posición abierta.', 'ENGINE', 'MODERATE', 'Verificar mecanismo del IMRC, mangueras de vacío o solenoide de control.', 'CAUTION'),
('P1372', 'Desviación de Carrera de Elevación de Válvula (Porsche Variocam)', 'Falla en el sistema de levantamiento variable de válvulas.', 'ENGINE', 'HIGH', 'Revisar actuador VarioCam, presión de aceite y estado del árbol de levas.', 'STOP_DRIVING'),
('P053F', 'Presión de Combustible de Arranque en Frío (Land Rover)', 'La bomba de alta presión (HPFP) no genera presión suficiente durante el arranque inicial.', 'ENGINE', 'HIGH', 'Verificar bomba de alta presión, sensor de presión de riel y desgaste del seguidor (cam follower).', 'STOP_DRIVING'),
('P1B00', 'Sistema de Gestión de Energía Híbrida / BMS (Europeos)', 'El sistema de gestión de baterías detectó una anomalía en carga/descarga.', 'ENGINE', 'HIGH', 'Verificar cables HV, temperatura de batería y actualizar software BMS.', 'STOP_DRIVING')
INSERT INTO public.dtc_codes (code, description_es, description_en, system, severity, possible_causes, urgency) VALUES 
('C1A00', 'Módulo de Control de Suspensión Neumática (Land Rover/Porsche)', 'Falla en el compresor o módulo de la suspensión de aire.', 'CHASSIS', 'HIGH', 'Revisar relé del compresor, fugas en balonas de aire y bloque de válvulas.', 'STOP_DRIVING'),
('P0A8F', 'Rendimiento del Sistema de Batería de 14V (Start-Stop)', 'La batería auxiliar o principal no puede mantener el voltaje para Auto Start-Stop.', 'HYBRID', 'MODERATE', 'Probar batería AGM, reemplazar si el SOH (State of Health) es bajo. Resetear BMS.', 'CAUTION'),
('P0512', 'Circuito de Petición de Motor de Arranque', 'Falla en el circuito de activación del relé de arranque desde el sistema Start-Stop o botón de encendido.', 'ENGINE', 'MODERATE', 'Revisar relé de arranque, módulo inmovilizador y botón push-to-start.', 'CAUTION'),
('P1193', 'Circuito del Sensor de Temperatura de Admisión Alto (Chrysler/FCA)', 'Sensor IAT en corto.', 'ENGINE', 'LOW', 'Verificar cableado del sensor IAT, cambiar sensor si está internamente cortocircuitado.', 'MONITOR')
